p.m:
\displaystyle{\begin{aligned}
   \frac{5}{9} + \frac{17}{18}
        \amp = \frac{10}{18} + \frac{17}{18} \\
        \amp = \frac{10 + 17}{18} \\
        \amp = \frac{27}{18} \amp  \hbox{We can reduce this by dividing 9 into both the numerator and the denominator.}\\
        \amp = \frac{3}{2}
\end{aligned}
    }
